#include<bits/stdc++.h>
using namespace std;
const long long N=1000010,nulltag=-1111;
long long n,val[N],top[N],dfn[N],dfncnt,fa[N],siz[N],rnk[N],son[N],d[N],mod;
vector<long long> mp[N];
void dfs1(long long x,long long f=0)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=fa[x]&&i!=son[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long min1,tag;
    }a[N*3];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    void pushupd(long long x,long long v)
    {
        if(!x||v==nulltag)
        {
            return;
        }
        a[x].min1=v;
        a[x].tag=v;
    }
    void pushdown(long long x)
    {
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        if(tg==nulltag)
        {
            return;
        }
        pushupd(ls,tg);
        pushupd(rs,tg);
        a[x].tag=nulltag;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=nulltag;
        if(l==r)
        {
            a[x].min1=val[rnk[l]];
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushupd(x,v);
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,v);
        update(a[x].rson,l,r,v);
        pushup(x);
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e12;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        pushdown(x);
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
}t;
void update(long long x,long long y,long long v)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.update(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(dfn[x]>dfn[y])
    {
        swap(x,y);
    }
    t.update(1,dfn[x],dfn[y],v);
}
long long root;
long long find(long long x)
{
    if(x==root)
    {
        return -1;
    }
    if(dfn[x]>=dfn[root]||dfn[x]+siz[x]-1<dfn[root])
    {
        return 0;
    }
    long long now=root;
    while(top[now]!=top[x])
    {
        if(fa[top[now]]==x)
        {
            return top[now];
        }
        now=fa[top[now]];
    }
    return son[x];
}
long long getmin(long long x)
{
    long long v=find(x);
    if(v==-1)
    {
        return t.a[1].min1;
    }
    else if(v==0)
    {
        return t.getmin(1,dfn[x],dfn[x]+siz[x]-1);
    }
    else
    {
        long long ans=t.getmin(1,1,dfn[v]-1);
        if(dfn[v]+siz[v]-1!=n)
        {
            ans=min(ans,t.getmin(1,dfn[v]+siz[v],n));
        }
        return ans;
    }
}
int main()
{
    long long m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&val[i]);
    }
    scanf("%lld",&root);
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    while(m--)
    {
        long long op,x,y,z;
        scanf("%lld%lld",&op,&x);
        if(op==1)
        {
            root=x;
        }
        else if(op==2)
        {
            long long y,z;
            scanf("%lld%lld",&y,&z);
            update(x,y,z);
        }
        else
        {
            printf("%lld\n",getmin(x));
        }
    }
    return 0;
}
